head.script:
window.__VERCEL_TRACK_SUSPENSE_FALLBACK__ ||= function (boundaryId, routePathname, name, hasExplicitName, badFallback) {
  const fallbackCommits = (window.__VERCEL_SUSPENSE_FALLBACK_COMMITS__ ||= new Map());
  const fallbackRoutePathname = routePathname === undefined ? 'unknown' : routePathname;
  const fallbackNavigationContext =
    window.__VERCEL_ROUTER_CONTENT_RENDER_PENDING_TRANSITION__
      ? 'router_transition'
      : window.__VERCEL_ROUTER_TRANSITION_HAS_STARTED__
        ? 'non_router_transition'
        : 'initial_load';
  if (!fallbackCommits.has(boundaryId)) {
    fallbackCommits.set(boundaryId, {
      renderedAt: performance.now(),
      routePathname: fallbackRoutePathname,
      navigationContext: fallbackNavigationContext,
    });
    (window.__VERCEL_SUSPENSE_RENDER_TIMING_PENDING__ ||= []).push(boundaryId);
  }};
window.__VERCEL_TRACK_SUSPENSE_FALLBACK__?.("suspense-root-cdp-runtime");

